const rows = $input.all();

const firstValidRow = rows.find(r => r.json['Column 1'] && !r.json['Column 1'].toLowerCase().includes('column'));
if (!firstValidRow) return [{ json: { clinicMap: {} } }];
const baseNC = String(firstValidRow.json['Abnormal Non Critical (Email Only)'] || firstValidRow.json['Abnormal Non Critical'] || '');
const baseCrit = String(firstValidRow.json['Abnormal Critical (Call the patient to repreat the reading and call the clinic and text the NP)'] || firstValidRow.json['Abnormal Critical'] || '');

function extractBaseline(nc, crit) {
    const s_nc = nc.toUpperCase();
    const s_crit = crit.toUpperCase();

    const bpNC   = parseInt(s_nc.match(/BP\s*[>≥]\s*(\d+)/)?.[1] || 160, 10);
    const bpCrit = parseInt(s_crit.match(/BP\s*[>≥]\s*(\d+)/)?.[1] || 190, 10);

    return {
        bpHigh:     bpNC,
        bpHighCrit: bpCrit,
        fbs: parseInt((s_nc + ' ' + s_crit).match(/FBS\s*[>≥]\s*(\d+)/)?.[1] || 130, 10),
        rbs: parseInt((s_nc + ' ' + s_crit).match(/RBS\s*[>≥]\s*(\d+)/)?.[1] || 250, 10)
    };
}

const baseline = extractBaseline(baseNC, baseCrit);
const clinicMap = {};

for (const row of rows) {
    const r = row.json;
    const name = String(r['Column 1'] || r['Provider Name'] || '').trim();
    if (!name || name.toLowerCase().includes('column')) continue;

    const nc   = String(r['Abnormal Non Critical (Email Only)'] || r['Abnormal Non Critical'] || '').trim();
    const crit = String(r['Abnormal Critical (Call the patient to repreat the reading and call the clinic and text the NP)'] || r['Abnormal Critical'] || '').trim();
    const fullText = (nc + ' ' + crit).toUpperCase();

    const rules = {
        clinicName:          name,
        bpSystolicHighNC:    baseline.bpHigh,
        bpSystolicHighCrit:  baseline.bpHighCrit,
        fbsHigh:             baseline.fbs,
        rbsHigh:             baseline.rbs,
        rtmDays:             fullText.includes('2 CONSECUTIVE DAYS') ? 2 : 5,

        providerEmail: String(r['Provider Email ID'] || '')
            .split(/\s+and\s+|,/)
            .map(e => e.trim())
            .filter(e => e.includes('@')),

        npPhone: String(r['NP/PA Contact Details'] || '').trim()
            .replace(/[^\d]/g, '')
            .replace(/^1?(\d{10})$/, '+1$1'),

        clinicPhone:    String(r['Clinic Phone no'] || '').trim(),
        nurseMA:        String(r['Nurse/MA'] || '').trim(),
        pointOfContact: String(r['Clinic Point of Contact'] || '').trim(),
        emergencyContact: String(r['Emergency Contact (During Business Hours M-F 8AM-5PM Texas time'] || r['Emergency Contact'] || '').trim()
    };

    clinicMap[name.toLowerCase()] = rules;
}

return [{ json: { clinicMap } }];

const rows = $input.all();
const clinics = [];
for (const row of rows) {
  const r = row.json;
  const values = Object.values(r);
  const name = String(values[1] || '').trim();
  const key = String(values[2] || '').trim();
  const secret = String(values[3] || '').trim();
  const active = String(values[4] || '').trim().toUpperCase();
  if (active === 'YES') clinics.push({ name, key, secret });
}
return [{ json: { clinics } }];

const patientItems = $('Merge Patients').all();
const patientMap = {};
for (const p of patientItems) { if (p.json && p.json.__empty) continue; patientMap[p.json.patientId] = p.json; }

const clinicMapRaw = $('Build Threshold Map').first().json.clinicMap || {};
const clinicMap = {};
for (const key in clinicMapRaw) { clinicMap[key.trim().toLowerCase()] = clinicMapRaw[key]; }

function normName(s) {
  return String(s || '').toLowerCase()
    .replace(/[.,&'/()\-]/g, ' ')
    .replace(/\b(pllc|llc|pc|pa|md|do|np|inc|incorporated|group|the|of|and)\b/g, ' ')
    .replace(/\s+/g, ' ').trim();
}
function stem(t) { return t.endsWith('s') && t.length > 3 ? t.slice(0, -1) : t; }
function tokenSet(s) { return [...new Set(normName(s).split(' ').filter(Boolean).map(stem))]; }
function levRatio(a, b) {
  if (a === b) return 1;
  if (!a.length || !b.length) return 0;
  const m = a.length, n = b.length;
  const dp = Array.from({ length: m + 1 }, (_, i) => [i, ...new Array(n).fill(0)]);
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = Math.min(dp[i-1][j] + 1, dp[i][j-1] + 1, dp[i-1][j-1] + (a[i-1] === b[j-1] ? 0 : 1));
  return 1 - dp[m][n] / Math.max(m, n);
}
function scoreSets(A, B) {
  if (!A.length || !B.length) return 0;
  const inter = A.filter(t => B.includes(t)).length;
  const union = new Set([...A, ...B]).size;
  const jaccard = inter / union;
  const contain = inter / Math.min(A.length, B.length);
  const charR   = levRatio([...A].sort().join(' '), [...B].sort().join(' '));
  return Math.max(jaccard, charR, 0.5 * contain + 0.5 * jaccard);
}

// Precompute clinic-key token sets ONCE
const clinicKeys = Object.keys(clinicMap).map(k => ({ k, ts: tokenSet(k) }));

// Resolve each distinct clinic name ONCE (memoized) — prevents the per-reading Levenshtein blowup
const resolveCache = new Map();
function findClinicInfo(apiName) {
  const needle = String(apiName || '').trim().toLowerCase();
  if (resolveCache.has(needle)) return resolveCache.get(needle);

  let result;
  if (clinicMap[needle]) {
    result = clinicMap[needle];
  } else {
    const nts = tokenSet(needle);
    const ACCEPT = 0.72, MARGIN = 0.12;
    let best = { s: -1, k: null }, second = { s: -1 };
    for (const ck of clinicKeys) {
      const s = scoreSets(nts, ck.ts);
      if (s > best.s) { second = best; best = { s, k: ck.k }; }
      else if (s > second.s) { second = { s }; }
    }
    result = (best.k && best.s >= ACCEPT && (best.s - second.s) >= MARGIN) ? clinicMap[best.k] : {};
    if (result && Object.keys(result).length) console.log(`[CLINIC-MATCH] "${apiName}" -> "${best.k}" (${best.s.toFixed(2)})`);
    else console.warn(`[CLINIC-NOMATCH] "${apiName}" (best "${best.k}" ${best.s >= 0 ? best.s.toFixed(2) : 0})`);
  }
  resolveCache.set(needle, result);
  return result;
}

const items = $input.all().filter(it => it.json && !it.json.__empty);
const enriched = [];
let droppedInactiveCount = 0, droppedOldCount = 0, activeKeptCount = 0;

if (!items.length) { return [{ json: { __empty: true, notes: 'No readings to enrich' } }]; }

const lookbackHours = 264;
const cutoffTime = new Date(Date.now() - (lookbackHours * 60 * 60 * 1000));

for (const item of items) {
  const r = item.json;
  const patient = patientMap[r.patient_id || r.patientId];
  if (patient) {
    const readingTime = new Date(r.timestamp || r.date_recorded || r.date);
    if (readingTime < cutoffTime) { droppedOldCount++; continue; }
    const cNameRaw = r.__clinicName || patient.groupName || '';
    const clinicInfo = findClinicInfo(cNameRaw);
    enriched.push({ json: { ...r, patientName: patient.patientName, patientPhone: patient.phone, clinicName: cNameRaw, clinic: clinicInfo } });
    activeKeptCount++;
  } else { droppedInactiveCount++; }
}

console.log(`[DEBUG] Enrich Data: Kept ${activeKeptCount} RECENT readings. Dropped ${droppedInactiveCount} INACTIVE and ${droppedOldCount} OLD readings. (distinct clinics resolved: ${resolveCache.size})`);
return enriched.length ? enriched : [{ json: { __empty: true, notes: 'No recent active readings found' } }];

// ===== CONFIG =====
const REMINDERS_ENABLED = true;
const PROGRAM_START      = '2026-06-22';
const COOLDOWN_DAYS      = 20;
const MAX_SMS_PER_RUN    = 2200; // hard cap — total patients is 2139, this catches runaway loops
const LADDER = [
  { day: 2,  action: 'SMS',   type: 'DAY2_SMS' },
  { day: 4,  action: 'SMS',   type: 'DAY4_SMS' },
  { day: 5,  action: 'VOICE', type: 'DAY5_VOICE' },
  { day: 7,  action: 'SMS',   type: 'DAY7_SMS' },
  { day: 9,  action: 'SMS',   type: 'DAY9_SMS' },
  { day: 10, action: 'VOICE', type: 'DAY10_VOICE' },
];
const FINAL_TYPE = 'DAY10_VOICE';
// ==================

const DAY_MS = 86400000;
const now = new Date();

function chicagoDay(d) {
  if (!d || isNaN(d)) return null;
  return new Intl.DateTimeFormat('en-CA', { timeZone: 'America/Chicago' }).format(d instanceof Date ? d : new Date(d));
}
function daysDiff(fromDate, toDate) {
  const f = chicagoDay(fromDate), t = chicagoDay(toDate);
  if (!f || !t) return 0;
  return Math.floor((new Date(t) - new Date(f)) / DAY_MS);
}
function parseMDY(s) {
  if (!s) return null;
  const [m, d, y] = String(s).split('/').map(Number);
  if (!y || isNaN(y)) return new Date(s);
  return new Date(Date.UTC(y, m - 1, d, 18, 0, 0));
}
function parseYMD(s) {
  const [y, m, d] = String(s).split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d, 18, 0, 0));
}

const programStart = parseYMD(PROGRAM_START);
const todayStr     = chicagoDay(now);

const enrichedItems = $input.all();
const patientsList  = $('Merge Patients').all();

// FAIL CLOSED: empty/failed readings must not flag everyone
const hasReadings = enrichedItems.some(i => i.json && !i.json.__empty);
if (!hasReadings) {
  console.warn('[REMINDER] readings empty/failed — skipping (fail-closed).');
  return [{ json: { __noRemindersNeeded: true, reason: 'fail-closed' } }];
}

// Last reading time per patient
const lastReadingMap = {};
for (const it of enrichedItems) {
  const r = it.json; if (r.__empty) continue;
  const pid = String(r.patientId || r.patient_id || '').trim();
  const t = new Date(r.timestamp || r.date_recorded || r.date);
  if (pid && !isNaN(t) && (!lastReadingMap[pid] || t > lastReadingMap[pid])) lastReadingMap[pid] = t;
}

// Reminder history per patient + same-day dedup set
const hist = {};
const alreadySentToday = new Set(); // patients who already got ANY reminder today
try {
  for (const row of $('Load Reminder History').all()) {
    const pid   = String(row.json.patient_id || '').trim();
    const type  = String(row.json.type || '').trim();
    const rawTs = String(row.json.timestamp || '').trim();
    if (!pid || !type || !rawTs) continue;
    const d = rawTs.includes('/') ? parseMDY(rawTs) : new Date(rawTs);
    if (!d || isNaN(d)) continue;
    (hist[pid] = hist[pid] || []).push({ type, date: d });
    // Track anyone already contacted today (same Chicago calendar date)
    if (chicagoDay(d) === todayStr) alreadySentToday.add(pid);
  }
} catch (e) { console.log('[ERROR] history load:', e.message); }

// FIRST RUN: if ReminderLog has zero entries ever, blast everyone
const isFirstRun = Object.keys(hist).length === 0;
if (isFirstRun) console.log('[REMINDER] FIRST RUN detected — sending SMS to all non-compliant patients.');
console.log(`[REMINDER] Already sent today: ${alreadySentToday.size} patients (same-day dedup)`);

const out = [];
const counts = { SMS:0, VOICE:0, compliant:0, cooldown:0, nothingDue:0, noPhone:0, skippedToday:0 };
const bySrc  = { smartmeter:{SMS:0,VOICE:0,total:0}, tenovi:{SMS:0,VOICE:0,total:0} };

for (const p of patientsList) {
  const pj = p.json; if (pj.__empty) continue;
  const pid = String(pj.patientId || '').trim(); if (!pid) continue;
  const src = pj.__source === 'tenovi' ? 'tenovi' : 'smartmeter';
  bySrc[src].total++;

  // HARD CAP: never exceed MAX_SMS_PER_RUN in one run
  if (counts.SMS >= MAX_SMS_PER_RUN) {
    console.warn(`[REMINDER] HARD CAP reached (${MAX_SMS_PER_RUN}) — stopping to prevent runaway spend.`);
    break;
  }

  // SAME-DAY DEDUP: already contacted today → skip entirely
  if (alreadySentToday.has(pid)) { counts.skippedToday++; continue; }

  const last = lastReadingMap[pid] || null;

  // Compliant: read within last 48 hours
  if (last && (now - last) < 2 * DAY_MS) { counts.compliant++; continue; }

  const phone = pj.phone;
  const phoneValid = phone && String(phone).replace(/\D/g, '').length >= 10;

  if (!phoneValid) {
    counts.noPhone++;
    out.push({ json: {
      patientId: pid, patientName: pj.patientName, patientPhone: '', clinicName: pj.groupName,
      source: src, modules: pj.modules || 'RPM', daysMissing: 0,
      actionType: 'DAY2_SMS_NOPHONE', action: 'NO_CONTACT', logStatus: 'NO_PHONE'
    }});
    continue;
  }

  // ── FIRST RUN: blast everyone non-compliant ────────────────────────
  if (isFirstRun) {
    out.push({ json: {
      patientId: pid, patientName: pj.patientName, patientPhone: phone, clinicName: pj.groupName,
      source: src, modules: pj.modules || 'RPM', daysMissing: 0,
      actionType: 'DAY2_SMS', action: 'SMS', logStatus: 'SMS_SENT'
    }});
    counts.SMS++;
    bySrc[src].SMS++;
    continue;
  }

  // ── NORMAL LADDER (all runs after first) ──────────────────────────
  const rows = hist[pid] || [];

  let lastFinal = null;
  for (const h of rows) {
    if (h.type.replace('_NOPHONE', '') === FINAL_TYPE && (!last || chicagoDay(h.date) > chicagoDay(last))) {
      if (!lastFinal || h.date > lastFinal) lastFinal = h.date;
    }
  }

  if (lastFinal && daysDiff(lastFinal, now) < COOLDOWN_DAYS) { counts.cooldown++; continue; }

  let anchor;
  if (lastFinal) {
    const lfStr = chicagoDay(lastFinal);
    const [lfy, lfm, lfd] = lfStr.split('-').map(Number);
    anchor = new Date(Date.UTC(lfy, lfm - 1, lfd + COOLDOWN_DAYS, 18, 0, 0));
    if (last && last > anchor) anchor = last;
  } else if (last) {
    anchor = last;
  } else {
    anchor = programStart;
  }
  if (daysDiff(programStart, anchor) < 0) anchor = programStart;

  const daysIn = daysDiff(anchor, now);
  if (daysIn < LADDER[0].day) { counts.nothingDue++; continue; }

  const firedThisLadder = rows
    .filter(h => h.date >= anchor)
    .map(h => h.type.replace('_NOPHONE', ''));
  let maxFiredDay = -1;
  for (const rung of LADDER) if (firedThisLadder.includes(rung.type) && rung.day > maxFiredDay) maxFiredDay = rung.day;

  let target = null;
  for (const rung of LADDER) if (rung.day <= daysIn && rung.day > maxFiredDay) target = rung;
  if (!target) { counts.nothingDue++; continue; }

  out.push({ json: {
    patientId: pid, patientName: pj.patientName, patientPhone: phone, clinicName: pj.groupName,
    source: src, modules: pj.modules || 'RPM', daysMissing: daysIn,
    actionType: target.type, action: target.action,
    logStatus: target.action === 'SMS' ? 'SMS_SENT' : 'VOICE_QUEUED'
  }});
  counts[target.action]++;
  bySrc[src][target.action]++;
}

console.log(`[REMINDER] FIRST_RUN=${isFirstRun} | SMS=${counts.SMS}/${MAX_SMS_PER_RUN} cap | VOICE=${counts.VOICE} | compliant=${counts.compliant} skippedToday=${counts.skippedToday} cooldown=${counts.cooldown} nothingDue=${counts.nothingDue} noPhone=${counts.noPhone}`);
console.log(`[REMINDER][BY SOURCE] SmartMeter ${JSON.stringify(bySrc.smartmeter)} | Tenovi ${JSON.stringify(bySrc.tenovi)}`);

if (!REMINDERS_ENABLED) {
  console.warn('[REMINDER] REMINDERS_ENABLED=false — computed only, sending nothing.');
  return [{ json: { __noRemindersNeeded: true, reason: 'disabled' } }];
}
return out.length ? out : [{ json: { __noRemindersNeeded: true } }];

const items = $input.all();
const anomalies = [];
const nowCST = new Date().toLocaleString("en-US", {timeZone: "America/Chicago", year: "numeric", month: "2-digit", day: "2-digit", hour: "2-digit", minute: "2-digit", hour12: true});

if (items.length === 1 && items[0].json.__empty) {
    return [{ json: { __noAnomalies: true, note: "No data" } }];
}

const alreadyLogged = new Set();
try {
  const auditRows = $("Load Today\'s Alert IDs").all();
  for (const row of auditRows) {
    const rid = String(row.json.reading_id || "").trim();
    if (rid) alreadyLogged.add(rid);
  }
} catch(e) {}

const seenThisRun = new Set();
let skipNoClinic = 0, skipNoClinicTenovi = 0, skipOld = 0, skipOldTenovi = 0;

function flag(r, clinic, alertType, label, value, unit, threshold, tier, direction) {
  const readingId = String(r.reading_id || r.alert_id || r.readingId || r.id || "");
  const pId = String(r.patient_id || r.patientId || "");
  const dedupKey = pId + "|" + alertType + "|" + readingId;
  if (readingId && alreadyLogged.has(readingId)) return false;
  if (seenThisRun.has(dedupKey)) return false;

  seenThisRun.add(dedupKey);
  anomalies.push({ json: {
    alertType, label, tier, direction, value, unit, threshold,
    patientId: pId,
    patientName: r.patientName,
    clinicName: clinic.clinicName || r.__clinicName,
    deviceType: r.device_type || r.deviceType || r.reading_type || "",
    readingId,
    timestamp: r.timestamp || r.date_recorded || r.date || "",
    detectedAt: nowCST,
    providerEmail: clinic.providerEmail || "",
    npPhone: clinic.npPhone || "",
    actionInstruction: tier === "CRITICAL" ? "CRITICAL: Alert" : "NON-CRITICAL: Alert"
  }});
  return true;
}

const anomalyCutoff = new Date(Date.now() - (24 * 60 * 60 * 1000));

for (const item of items) {
  const r = item.json;
  if (!r.clinic || Object.keys(r.clinic).length === 0) {
    skipNoClinic++;
    if (r.__source === 'tenovi') skipNoClinicTenovi++;
    continue;
  }

  const rTime = new Date(r.timestamp || r.date_recorded || r.date);
  if (rTime < anomalyCutoff) {
    skipOld++;
    if (r.__source === 'tenovi') skipOldTenovi++;
    continue;
  }

  const dt = String(r.device_type||r.deviceType||r.reading_type||"").toLowerCase();
  if (dt.includes("blood_pressure") || dt.includes("bp")) {
    const sys = parseFloat(r.systolic || r.systolic_mmhg);
    if (!isNaN(sys)) {
       if (r.clinic.bpSystolicHighCrit && sys >= r.clinic.bpSystolicHighCrit) flag(r,r.clinic,"BP_HIGH","High Systolic",sys,"mmHg",r.clinic.bpSystolicHighCrit,"CRITICAL","HIGH");
       else if (r.clinic.bpSystolicHighNC && sys >= r.clinic.bpSystolicHighNC) flag(r,r.clinic,"BP_HIGH","High Systolic",sys,"mmHg",r.clinic.bpSystolicHighNC,"NON_CRITICAL","HIGH");
    }
  }
  const isGlucose = dt.includes("blood_glucose") || dt.includes("glucose");
  if (isGlucose) {
    const gv = parseFloat(r.glucose || r.blood_glucose_mgdl || r.value || NaN);
    const mtype = String(r.measurement_type||r.reading_type||"").toUpperCase();
    const isFasting = mtype.includes("FBS") || mtype.includes("FASTING") || r.before_meal === true;
    const highThr = isFasting ? r.clinic.fbsHigh : r.clinic.rbsHigh;
    if (!isNaN(gv) && highThr && gv > highThr) {
        flag(r,r.clinic,"GLUCOSE_HIGH","High Glucose",gv,"mg/dL",highThr,gv > 250 ? "CRITICAL" : "NON_CRITICAL","HIGH");
    }
  }
}
console.log(`[DEBUG] Detect: skipped ${skipNoClinic} no-clinic (${skipNoClinicTenovi} Tenovi), ${skipOld} older-than-24h (${skipOldTenovi} Tenovi). Fired ${anomalies.length}.`);
return anomalies;

const items = $input.all();

  let CANON = [];
  try {
    CANON = ($('Build Clinic List').first().json.clinics || []).map(c => c.name).filter(Boolean);
  } catch (e) { CANON = []; }

  function normName(s) {
    return String(s || '')
      .toLowerCase()
      .replace(/[.,&'/()\-]/g, ' ')
      .replace(/\b(pllc|llc|pc|pa|md|do|np|inc|incorporated|group|the|of|and)\b/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  }
  function stem(t) { return t.endsWith('s') && t.length > 3 ? t.slice(0, -1) : t; }
  function tokenSet(s) { return [...new Set(normName(s).split(' ').filter(Boolean).map(stem))]; }
  function levRatio(a, b) {
    if (a === b) return 1;
    if (!a.length || !b.length) return 0;
    const m = a.length, n = b.length;
    const dp = Array.from({ length: m + 1 }, (_, i) => [i, ...new Array(n).fill(0)]);
    for (let j = 0; j <= n; j++) dp[0][j] = j;
    for (let i = 1; i <= m; i++)
      for (let j = 1; j <= n; j++)
        dp[i][j] = Math.min(dp[i-1][j] + 1, dp[i][j-1] + 1, dp[i-1][j-1] + (a[i-1] === b[j-1] ? 0 : 1));
    return 1 - dp[m][n] / Math.max(m, n);
  }
  function nameScore(a, b) {
    const A = tokenSet(a), B = tokenSet(b);
    if (!A.length || !B.length) return 0;
    const inter = A.filter(t => B.includes(t)).length;
    const union = new Set([...A, ...B]).size;
    const jaccard = inter / union;
    const contain = inter / Math.min(A.length, B.length);
    const charR   = levRatio([...A].sort().join(' '), [...B].sort().join(' '));
    return Math.max(jaccard, charR, 0.5 * contain + 0.5 * jaccard);
  }
  function canonical(name) {
    const ACCEPT = 0.72, MARGIN = 0.12;
    if (!CANON.length) return { name, exact: true };
    const scored = CANON.map(c => ({ c, s: nameScore(name, c) })).sort((x, y) => y.s - x.s);
    const best = scored[0], second = scored[1] || { s: 0 };
    if (best && best.s >= 0.999) return { name: best.c, exact: true };
    if (best && best.s >= ACCEPT && (best.s - second.s) >= MARGIN) {
      console.log(`[CLINIC-MATCH] "${name}" → "${best.c}" (${best.s.toFixed(2)})`);
      return { name: best.c, exact: false };
    }
    console.warn(`[CLINIC-NOMATCH] "${name}" kept as-is (best "${best ? best.c : '-'}" ${best ? best.s.toFixed(2) : 0})`);
    return { name, exact: false };
  }

  const groups = {};

  for (const item of items) {
    const a = item.json;
    if (!a.alertType) continue;

    const tier = a.tier === 'CRITICAL' ? 'CRITICAL' : 'NON_CRITICAL';
    const resolved = canonical(a.clinicName || 'Unknown Clinic');
    const clinicName = resolved.name;
    const key = clinicName + '|' + tier;

    if (!groups[key]) {
      groups[key] = {
        clinicName,
        tier,
        detectedAt:    a.detectedAt || '',
        providerEmail: a.providerEmail || '',
        npPhone:       a.npPhone || '',
        _providerLocked: false,
        alerts: []
      };
    }
    const g = groups[key];

    if (!g._providerLocked && resolved.exact && a.providerEmail) {
      g.providerEmail = a.providerEmail;
      g.npPhone = a.npPhone || g.npPhone;
      g._providerLocked = true;
    } else if (!g.providerEmail && a.providerEmail) {
      g.providerEmail = a.providerEmail;
      g.npPhone = a.npPhone || g.npPhone;
    }

    g.alerts.push({
