 function hmacSha1(keyBytes, msgBytes) {
   const BLOCK=64;
   let k=[...keyBytes];
   if(k.length>BLOCK) k=sha1(k);
   while(k.length<BLOCK) k.push(0);
   const ipad=k.map(b=>b^0x36);
   const opad=k.map(b=>b^0x5c);
   return sha1([...opad,...sha1([...ipad,...msgBytes])]);
