      } catch (e) {
        tenoviErrors++;
        console.error(`[ERROR] [Tenovi] patient=${patient.patientId}:`, e.message);
      }
    }
  });
  await Promise.all(runners);
  console.log(`[DEBUG] [Tenovi] Total: ${tenoviVitals} vitals, ${tenoviRtm} RTM-activity, ${tenoviErrors} errors`);
} catch (e) {
  console.error('[ERROR] [Tenovi] readings block failed:', e.message);
  errors.push({ source: 'tenovi', error: e.message });
}
console.log(`[DEBUG] [Tenovi] Total readings: ${allRecords.length}`);
return allRecords.length ? allRecords.map(r => ({ json: r })) : [{ json: { __empty: true, __source: 'tenovi', notes: 'No Tenovi readings', errors } }];

